(function () {
  /* ═══════════════════════════════════════════════
               Embedded XLSX as base64 — used for download
               and as ExcelJS source
            ═══════════════════════════════════════════════ */
  const XLSX_B64 =
    "";

  /* ═══════════════════════════════════════════════
               Pre-extracted sheet data (no ExcelJS parsing needed
               for the static template — we use ExcelJS for
               employee-data-merged rendering)
            ═══════════════════════════════════════════════ */

  let workbook = null;
  let activeSheet = "C1";
  const sheetCache = {};

  /* Border shortcode → CSS */
  const BORDER_CSS = {
    thin: "1px solid #aaa",
    medium: "2px solid #555",
    thick: "3px solid #222",
    hair: "1px solid #ddd",
    dashDot: "1px dashed #bbb",
    dashed: "1px dashed #bbb",
    dotted: "1px dotted #bbb",
    double: "3px double #888",
    mediumDashDot: "2px dashed #777",
    slantDashDot: "1px dashed #bbb",
  };

  /* ── Init ── */
  window.switchTab = switchTab;

  init();

  async function init() {
    try {
      const bytes = b64ToBytes(XLSX_B64);

      /* Set download link */
      const blob = new Blob([bytes], {
        type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
      });
      const url = URL.createObjectURL(blob);
      document.getElementById("btnDownload").href = url;
      const d2 = document.getElementById("btnDownload2");
      if (d2) d2.href = url;

      /* Parse with ExcelJS */
      workbook = new ExcelJS.Workbook();
      await workbook.xlsx.load(bytes.buffer);

      /* Render first sheet */
      showContent();
      renderSheet("C1");
    } catch (e) {
      console.error("PDS render error:", e);
      showError();
    }
  }

  function showContent() {
    document.getElementById("pdsLoading").style.display = "none";
    document.getElementById("sheetContent").style.display = "block";
  }

  function showError() {
    document.getElementById("pdsLoading").style.display = "none";
    const err = document.getElementById("pdsError");
    err.classList.remove("d-none");
    err.style.removeProperty("display");
    err.style.display = "flex";
  }

  function switchTab(name, el) {
    activeSheet = name;
    document
      .querySelectorAll(".pds-tab")
      .forEach((t) => t.classList.remove("active"));
    el.classList.add("active");
    if (workbook) renderSheet(name);
  }

  /* ── Render a worksheet into #sheetContent ── */
  function renderSheet(sheetName) {
    if (sheetCache[sheetName]) {
      document.getElementById("sheetContent").innerHTML = sheetCache[sheetName];
      return;
    }

    const ws = workbook.getWorksheet(sheetName);
    if (!ws) return;

    /* ── Build merged-cell map ── */
    const mergedTL = {}; // "r,c" → {rs, cs}
    const mergedSkip = new Set();

    ws.model.merges &&
      ws.model.merges.forEach((addr) => {
        // addr like "A1:D3"
        const [tl, br] = addr.split(":");
        const tlC = ws.getCell(tl);
        const brC = ws.getCell(br);
        const rs = brC.row - tlC.row + 1;
        const cs = brC.col - tlC.col + 1;
        mergedTL[`${tlC.row},${tlC.col}`] = { rs, cs };
        for (let r = tlC.row; r <= brC.row; r++) {
          for (let c = tlC.col; c <= brC.col; c++) {
            if (r !== tlC.row || c !== tlC.col) {
              mergedSkip.add(`${r},${c}`);
            }
          }
        }
      });

    /* ── Column widths ── */
    const colPx = {};
    ws.columns.forEach((col) => {
      if (col && col.number) {
        const w = col.width || 8.43;
        colPx[col.number] = Math.max(20, Math.round(w * 6.8));
      }
    });
    // Determine last visible column
    let maxCol = ws.columnCount;

    /* ── Build table ── */
    let html = `<table class="pds-table"><colgroup>`;
    for (let c = 1; c <= maxCol; c++) {
      html += `<col style="width:${colPx[c] || 52}px">`;
    }
    html += `</colgroup>`;

    ws.eachRow({ includeEmpty: true }, (row, rn) => {
      const rh = row.height ? Math.max(14, Math.round(row.height * 1.34)) : 18;
      html += `<tr style="height:${rh}px;">`;

      for (let cn = 1; cn <= maxCol; cn++) {
        const key = `${rn},${cn}`;
        if (mergedSkip.has(key)) continue;

        const cell = row.getCell(cn);
        const merge = mergedTL[key];

        let style = ``;

        /* Background */
        const fill = cell.style?.fill;
        if (fill?.type === "pattern" && fill.fgColor) {
          const argb = fill.fgColor.argb || fill.fgColor.rgb || "";
          if (
            argb &&
            !["00000000", "FFFFFFFF", "FF000000"].includes(argb) &&
            argb.length >= 6
          ) {
            style += `background:#${argb.slice(-6)};`;
          }
        }

        /* Font */
        const font = cell.style?.font;
        if (font) {
          if (font.bold) style += "font-weight:bold;";
          if (font.italic) style += "font-style:italic;";
          if (font.size)
            style += `font-size:${Math.max(6, Math.round(font.size * 0.88))}px;`;
          if (
            font.color?.argb &&
            !["FF000000", "00000000"].includes(font.color.argb)
          ) {
            style += `color:#${font.color.argb.slice(-6)};`;
          }
        }

        /* Alignment */
        const aln = cell.style?.alignment;
        if (aln) {
          const hMap = {
            center: "center",
            right: "right",
            left: "left",
            justify: "justify",
            distributed: "center",
          };
          const vMap = {
            middle: "middle",
            top: "top",
            bottom: "bottom",
            distributed: "middle",
          };
          if (aln.horizontal && hMap[aln.horizontal])
            style += `text-align:${hMap[aln.horizontal]};`;
          if (aln.vertical && vMap[aln.vertical])
            style += `vertical-align:${vMap[aln.vertical]};`;
          if (aln.wrapText) style += "white-space:pre-wrap;";
        }

        /* Borders */
        const bdr = cell.style?.border;
        if (bdr) {
          ["top", "bottom", "left", "right"].forEach((side) => {
            const s = bdr[side]?.style;
            if (s && BORDER_CSS[s]) style += `border-${side}:${BORDER_CSS[s]};`;
          });
        }

        /* Attributes */
        const rsAttr = merge ? ` rowspan="${merge.rs}"` : "";
        const csAttr = merge ? ` colspan="${merge.cs}"` : "";

        /* Cell value */
        let val = "";
        const ct = cell.type;
        if (ct === 2)
          val =
            cell.value !== null && cell.value !== undefined
              ? escH(String(cell.value))
              : "";
        else if (ct === 3) val = escH(String(cell.value || ""));
        else if (ct === 4) val = cell.value ? escH(fmtDate(cell.value)) : "";
        else if (ct === 5) val = cell.value ? "TRUE" : "FALSE";
        else if (ct === 6) {
          const rv = cell.result;
          val = rv !== null && rv !== undefined ? escH(String(rv)) : "";
        } else if (cell.value) val = escH(String(cell.value));

        html += `<td${rsAttr}${csAttr} style="${style}">${val}</td>`;
      }
      html += "</tr>";
    });

    html += "</table>";
    sheetCache[sheetName] = html;
    document.getElementById("sheetContent").innerHTML = html;

    /* Cell count info */
    const cellCount = html.match(/<td/g)?.length || 0;
    document.getElementById("cellCount").textContent =
      `${ws.rowCount} rows · ${maxCol} columns · ${ws.model.merges?.length || 0} merged regions`;
  }

  /* ── Helpers ── */
  function b64ToBytes(b64) {
    const bin = atob(b64);
    const arr = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
    return arr;
  }

  function escH(s) {
    return s
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/\n/g, "<br>");
  }

  function fmtDate(d) {
    if (!(d instanceof Date)) return String(d);
    const dd = String(d.getDate()).padStart(2, "0");
    const mm = String(d.getMonth() + 1).padStart(2, "0");
    const yyyy = d.getFullYear();
    return `${dd}/${mm}/${yyyy}`;
  }
})();
